public class ExFlow {
    static int compute(int x) {
        try {
            if (x == 0) throw new ArithmeticException("zero!");
            return 100 / x;
        } catch (ArithmeticException e) {
            System.out.println("Caught: " + e.getMessage());
            return -1;
        } finally {
            System.out.println("Finally runs always");
        }
    }

    public static void main(String[] args) {
        System.out.println(compute(5));   // 20, finally, then prints 20
        System.out.println(compute(0));   // caught, finally, then prints -1
    }
}

