public class Exercise2 {
    interface Flyable {
        default String move() { return "Fly"; }
        String describe();
    }

    interface Swimmable {
        default String move() { return "Swim"; }
    }

    static abstract class Animal {
        String name;
        Animal(String name) { this.name = name; }
        abstract String sound();
        String info() { return name + " says " + sound(); }
    }

    static class Duck extends Animal implements Flyable, Swimmable {
        Duck(String name) { super(name); }

        @Override
        public String sound() { return "Quack"; }

        @Override
        public String describe() { return name + " is a duck"; }

        @Override
        public String move() { return "Fly and Swim"; }  // resolves diamond
    }

    public static void main(String[] args) {
        Duck d = new Duck("Donald");
        Flyable f = d;
        Animal a = d;

        System.out.println(a.info());
        System.out.println(f.describe());
        System.out.println(f.move());
        System.out.println(d.move());

        System.out.println(a instanceof Swimmable);
        System.out.println(a instanceof Flyable);
    }
}

