public class Exercise4 {
    static void level3() {
        System.out.println("L3 start");
        throw new IllegalArgumentException("bad arg");
    }

    static void level2() {
        try {
            System.out.println("L2 try");
            level3();
            System.out.println("L2 after call");  // never reached
        } catch (NullPointerException e) {
            System.out.println("L2 catch NPE");
        } finally {
            System.out.println("L2 finally");
        }
    }

    static void level1() {
        try {
            System.out.println("L1 try");
            level2();
            System.out.println("L1 after call");  // never reached
        } catch (IllegalArgumentException e) {
            System.out.println("L1 catch: " + e.getMessage());
        } finally {
            System.out.println("L1 finally");
        }
    }

    public static void main(String[] args) {
        System.out.println("Main start");
        level1();
        System.out.println("Main end");
    }
}

// Design the following class hierarchy and demonstrate it in main():
//
// Abstract class: BankAccount
//   - private double balance (encapsulated)
//   - private String owner
//   - Constructor(owner, initialBalance): validates balance >= 0, throws
//     IllegalArgumentException if negative
//   - void deposit(double amount): validates amount > 0
//   - abstract void withdraw(double amount)
//   - double getBalance()    (getter)
//   - String getOwner()      (getter)
//   - String toString():     returns "[owner: balance]"
//
// Class: SavingsAccount extends BankAccount
//   - Has a minimum balance of 500.0 (constant)
//   - withdraw(): throws IllegalStateException if balance - amount < 500
//
// Class: CheckingAccount extends BankAccount
//   - Has an overdraft limit of 200.0 (constant)
//   - withdraw(): allows balance to go negative, but not below -200
//   - throws IllegalStateException if it would exceed overdraft
//
// In main():
//   - Create one of each, store in BankAccount[] array
//   - Deposit and withdraw from each via the array (polymorphic calls)
//   - Use try/catch to handle one illegal withdrawal gracefully
//   - Print all accounts using toString()

