public class Exercise5 {
    static abstract class BankAccount {
        private double balance;
        private String owner;

        BankAccount(String owner, double initialBalance) {
            if (initialBalance < 0)
                throw new IllegalArgumentException("Balance cannot be negative");
            this.owner = owner;
            this.balance = initialBalance;
        }

        void deposit(double amount) {
            if (amount <= 0)
                throw new IllegalArgumentException("Deposit must be positive");
            balance += amount;
        }

        abstract void withdraw(double amount);

        double getBalance() { return balance; }
        String getOwner()   { return owner; }

        protected void setBalance(double b) { balance = b; }

        @Override
        public String toString() {
            return String.format("[%s: %.2f]", owner, balance);
        }
    }

    static class SavingsAccount extends BankAccount {
        static final double MIN_BALANCE = 500.0;

        SavingsAccount(String owner, double initialBalance) {
            super(owner, initialBalance);
        }

        @Override
        void withdraw(double amount) {
            if (getBalance() - amount < MIN_BALANCE)
                throw new IllegalStateException(
                    "Cannot drop below minimum balance of " + MIN_BALANCE);
            setBalance(getBalance() - amount);
        }
    }

    static class CheckingAccount extends BankAccount {
        static final double OVERDRAFT_LIMIT = 200.0;

        CheckingAccount(String owner, double initialBalance) {
            super(owner, initialBalance);
        }

        @Override
        void withdraw(double amount) {
            if (getBalance() - amount < -OVERDRAFT_LIMIT)
                throw new IllegalStateException(
                    "Exceeds overdraft limit of " + OVERDRAFT_LIMIT);
            setBalance(getBalance() - amount);
        }
    }

    public static void main(String[] args) {
        BankAccount[] accounts = {
            new SavingsAccount("Alice", 1000.0),
            new CheckingAccount("Bob", 300.0)
        };

        accounts[0].deposit(200.0);
        accounts[0].withdraw(500.0);  // OK: 700 remaining (>= 500 min)

        accounts[1].deposit(100.0);
        accounts[1].withdraw(550.0);  // OK: -150 (within -200 overdraft)

        // Attempt an illegal savings withdrawal
        try {
            accounts[0].withdraw(400.0);  // Would leave 300 < 500 min
        } catch (IllegalStateException e) {
            System.out.println("Caught: " + e.getMessage());
        }

        for (BankAccount acc : accounts) {
            System.out.println(acc);
        }
    }
}

