import java.util.ArrayList;
import java.util.HashMap;
import java.util.Map;

public class Exercise7 {
    static class Student {
        private String name;
        private String id;

        Student(String id, String name) {
            this.id = id;
            this.name = name;
        }

        public String getName() { return name; }
        public String getId()   { return id; }

        @Override
        public String toString() { return "[" + id + "] " + name; }
    }

    static class GradeBook<T extends Student> {
        private HashMap<T, ArrayList<Integer>> records = new HashMap<>();

        public void enroll(T student) {
            records.putIfAbsent(student, new ArrayList<>());
        }

        public void addScore(T student, int score) {
            if (score < 0 || score > 100)
                throw new IllegalArgumentException(
                    "Score must be 0-100, got: " + score);
            if (!records.containsKey(student))
                throw new IllegalStateException(student + " not enrolled");
            records.get(student).add(score);
        }

        public double getAverage(T student) {
            ArrayList<Integer> scores = records.get(student);
            if (scores == null || scores.isEmpty())
                throw new IllegalStateException(
                    student + " has no scores");
            int sum = 0;
            for (int s : scores) sum += s;
            return (double) sum / scores.size();
        }

        public T getTopStudent() {
            T top = null;
            double topAvg = -1;
            for (Map.Entry<T, ArrayList<Integer>> entry : records.entrySet()) {
                T s = entry.getKey();
                ArrayList<Integer> sc = entry.getValue();
                if (sc.isEmpty()) continue;
                int sum = 0;
                for (int v : sc) sum += v;
                double avg = (double) sum / sc.size();
                if (avg > topAvg) { topAvg = avg; top = s; }
            }
            return top;
        }
    }

    public static void main(String[] args) {
        GradeBook<Student> book = new GradeBook<>();

        Student s1 = new Student("2025-001", "Ashik");
        Student s2 = new Student("2025-002", "Raisa");
        Student s3 = new Student("2025-003", "Kabir");

        book.enroll(s1);
        book.enroll(s2);
        book.enroll(s3);

        book.addScore(s1, 85);
        book.addScore(s1, 90);
        book.addScore(s1, 78);

        book.addScore(s2, 95);
        book.addScore(s2, 92);
        book.addScore(s2, 88);

        book.addScore(s3, 70);
        book.addScore(s3, 65);
        book.addScore(s3, 72);

        for (Student s : new Student[]{s1, s2, s3}) {
            System.out.printf("%s -> avg: %.2f%n", s, book.getAverage(s));
        }

        System.out.println("Top student: " + book.getTopStudent());
    }
}
